import React from "react";

function AboutPage() {
  return (
    <div>
      <h1>About CareerSphere</h1>
      <p>
        CareerSphere helps you create resumes, CVs, and personal blogs. Showcase your skills, experiences, and projects in a personalized manner!
      </p>
    </div>
  );
}

export default AboutPage;
